insert into wac_drama_script values (112001, 112, 93, '1', '0', '', '', '', '', '', '');
insert into wac_drama_script values (112002, 112, 3, '118511', 'wac_215_karin_talk_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112003, 112, 21, 'vo_wac_220215', 'vo_wac_220215_000', '0', '0', '', '', '', '');
insert into wac_drama_script values (112004, 112, 11, '118511', '【美食殿】のみなさん、\\n来ていただいてありがとうございます！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112005, 112, 91, '112004', '', '', '', '', '', '', '');
insert into wac_drama_script values (112006, 112, 3, '118511', 'wac_215_karin_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112007, 112, 3, '105811', 'wac_215_peko_oissu', '0', 'wac_215_talk_normal', '1', '0.2', '0.2', '');
insert into wac_drama_script values (112008, 112, 21, 'vo_wac_220215', 'vo_wac_220215_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (112009, 112, 11, '105811', 'カリンさん、オイッスー！\\nどうしたんですか？\\nランドソルの端っこに\\n呼び出したりなんかして。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112010, 112, 91, '112009', '', '', '', '', '', '', '');
insert into wac_drama_script values (112011, 112, 3, '105811', 'wac_215_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112012, 112, 3, '118511', 'wac_215_karin_talk_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112013, 112, 21, 'vo_wac_220215', 'vo_wac_220215_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (112014, 112, 11, '118511', '今日はみなさんにお願いしたい\\n重要な依頼があるんです。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112015, 112, 91, '112014', '', '', '', '', '', '', '');
insert into wac_drama_script values (112016, 112, 3, '118511', 'wac_215_karin_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112017, 112, 3, '106011', 'wac_215_talk_arm_crossed', '0', 'wac_215_talk_arm_crossed_loop', '1', '0.2', '0', '');
insert into wac_drama_script values (112018, 112, 21, 'vo_wac_220215', 'vo_wac_220215_003', '0', '0', '', '', '', '');
insert into wac_drama_script values (112019, 112, 11, '106011', '重要な依頼？\\nまた面倒くさいこと押し付けようと\\nしてんじゃないでしょうね……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112020, 112, 91, '112019', '', '', '', '', '', '', '');
insert into wac_drama_script values (112021, 112, 3, '106011', 'wac_215_idle_arm_crossed', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112022, 112, 3, '118511', 'wac_215_karin_talk_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112023, 112, 21, 'vo_wac_220215', 'vo_wac_220215_004', '0', '0', '', '', '', '');
insert into wac_drama_script values (112024, 112, 11, '118511', '実はこのたび景観向上事業として\\nランドソルを囲む壁に\\n絵を描いて、街を華やかにするという\\n計画を進めることになりまして。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112025, 112, 91, '112024', '', '', '', '', '', '', '');
insert into wac_drama_script values (112026, 112, 3, '118511', 'wac_215_karin_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112027, 112, 3, '106431', 'wac_215_shefy_humu', '0', 'wac_215_talk_normal', '1', '0.2', '0.2', '');
insert into wac_drama_script values (112028, 112, 21, 'vo_wac_220215', 'vo_wac_220215_005', '0', '0', '', '', '', '');
insert into wac_drama_script values (112029, 112, 11, '106431', 'ランドソルを囲む壁に絵を？\\nふぅん、楽しそうね。\\nここに描けばいいのかしら？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112030, 112, 91, '112029', '', '', '', '', '', '', '');
insert into wac_drama_script values (112031, 112, 3, '106431', 'wac_215_idle_normal2_joy', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112032, 112, 3, '118511', 'wac_215_karin_talk_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112033, 112, 21, 'vo_wac_220215', 'vo_wac_220215_006', '0', '0', '', '', '', '');
insert into wac_drama_script values (112034, 112, 11, '118511', 'はい。ここから始めて、\\nランドソルの壁をぐるっと一周\\n絵でいっぱいにしたいんです。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112035, 112, 91, '112034', '', '', '', '', '', '', '');
insert into wac_drama_script values (112036, 112, 3, '118511', 'wac_215_karin_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112037, 112, 3, '106431', 'wac_215_talk_sad', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112038, 112, 21, 'vo_wac_220215', 'vo_wac_220215_007', '0', '0', '', '', '', '');
insert into wac_drama_script values (112039, 112, 11, '106431', 'え？\u3000ランドソルの壁を……\\nぐるっと一周？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112040, 112, 91, '112039', '', '', '', '', '', '', '');
insert into wac_drama_script values (112041, 112, 3, '106431', 'wac_215_idle_sad', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112042, 112, 3, '118511', 'wac_215_karin_talk_wish', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112043, 112, 21, 'vo_wac_220215', 'vo_wac_220215_008', '0', '0', '', '', '', '');
insert into wac_drama_script values (112044, 112, 11, '118511', 'はい♪\u3000ランドソル中を\\n素敵な絵で飾ることができたら\\nとっても魅力的な街になると\\n思いませんか？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112045, 112, 91, '112044', '', '', '', '', '', '', '');
insert into wac_drama_script values (112046, 112, 3, '118511', 'wac_215_karin_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112047, 112, 3, '105911', 'wac_215_coccoro_talk_wish', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112048, 112, 21, 'vo_wac_220215', 'vo_wac_220215_009', '0', '0', '', '', '', '');
insert into wac_drama_script values (112049, 112, 11, '105911', 'それは……壮大な計画でございますね。\\nカリンさま。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112050, 112, 91, '112049', '', '', '', '', '', '', '');
insert into wac_drama_script values (112051, 112, 3, '105911', 'wac_215_coccoro_idle_wish', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112052, 112, 3, '105811', 'wac_215_peko_talk_guts2', '0', 'wac_215_peko_talk_guts2_loop', '1', '0.2', '0', '');
insert into wac_drama_script values (112053, 112, 21, 'vo_wac_220215', 'vo_wac_220215_010', '0', '0', '', '', '', '');
insert into wac_drama_script values (112054, 112, 11, '105811', 'わくわくします！\u3000やばいですね☆\\nじゃあ、王宮勤めの画家の人に\\n絵の描き方を教えてもらいましょう♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112055, 112, 91, '112054', '', '', '', '', '', '', '');
insert into wac_drama_script values (112056, 112, 3, '105811', 'wac_215_peko_idle_guts2', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112057, 112, 4, '105811', '0', '', '', '', '', '', '');
insert into wac_drama_script values (112058, 112, 4, '105911', '0', '', '', '', '', '', '');
insert into wac_drama_script values (112059, 112, 3, '105811', 'wac_215_idle_joy1', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112060, 112, 3, '105911', 'wac_215_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112061, 112, 3, '106431', 'wac_215_idle_surprise1', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112062, 112, 3, '106011', 'wac_215_kyaru_anger', '1', 'wac_215_talk_anger2', '1', '0.2', '0.2', '');
insert into wac_drama_script values (112063, 112, 21, 'vo_wac_220215', 'vo_wac_220215_011', '0', '0', '', '', '', '');
insert into wac_drama_script values (112064, 112, 11, '106011', '待って待って待って！！\\n待ちなさいってば！？\\nあんたたち、ランドソルの壁一周って\\nどんだけの長さがあると思ってんのよ！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112065, 112, 91, '112064', '', '', '', '', '', '', '');
insert into wac_drama_script values (112066, 112, 3, '106011', 'wac_215_idle_anger2', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112067, 112, 3, '106011', 'wac_215_talk_sad', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112068, 112, 21, 'vo_wac_220215', 'vo_wac_220215_012', '0', '0', '', '', '', '');
insert into wac_drama_script values (112069, 112, 11, '106011', '普通に歩くだけでもうんざりする\\nくらいの距離なのよ？\\nあたしたちだけじゃいくらなんでも……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112070, 112, 91, '112069', '', '', '', '', '', '', '');
insert into wac_drama_script values (112071, 112, 3, '106011', 'wac_215_idle_sad', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112072, 112, 3, '105911', 'wac_215_coccoro_talk_wish2', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112073, 112, 21, 'vo_wac_220215', 'vo_wac_220215_013', '0', '0', '', '', '', '');
insert into wac_drama_script values (112074, 112, 11, '105911', 'キャルさま、では、他のギルドにも\\nご協力いただくのはどうでしょう。\\nみなさまと力を合わせれば……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112075, 112, 91, '112074', '', '', '', '', '', '', '');
insert into wac_drama_script values (112076, 112, 3, '105911', 'wac_215_coccoro_idle_wish2', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112077, 112, 3, '106011', 'wac_215_kyaru_talk_doya', '0', 'wac_215_kyaru_talk_doya_loop', '1', '0.2', '0', '');
insert into wac_drama_script values (112078, 112, 21, 'vo_wac_220215', 'vo_wac_220215_014', '0', '0', '', '', '', '');
insert into wac_drama_script values (112079, 112, 11, '106011', '超やる気じゃないのコロ助……\\nああもう、仕方ないわね。\\nカリン、あんたそういうの得意でしょ？\\nコールオブなんとかっていうやつ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (112080, 112, 91, '112079', '', '', '', '', '', '', '');
insert into wac_drama_script values (112081, 112, 3, '106011', 'wac_215_idle_arm_crossed', '1', '', '', '0.2', '', '');
