insert into wac_drama_script values (1212009, 1212, 11, '100811', 'ああ……美しい……\\n美しい以外にこれを\\n表現する言葉が見当たらないよ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (1212010, 1212, 91, '0', '', '', '', '', '', '', '');
