insert into wac_drama_script values (1212012, 1212, 11, '100811', '未完の美なんて言葉もあるけど、\\nそんなのボクには関係ないね。\\n完全にして完璧な美。\\nそれがボク！\u3000ああ……美しい……', '10', '1', '1', '0', '0', '0.5');
