insert into wac_drama_script values (2112012, 2112, 11, '100511', '一筆入魂で\\n正義の心を込める方が大切ッス。\\nこれで街の悪い人たちも\\n正義に目覚めてくれるといいッスね！', '10', '1', '1', '0', '0', '0.5');
