insert into wac_drama_script values (2612009, 2612, 11, '104011', 'えへへ、きちんと上手に描けました。\\n黙々と作業するのは嫌いじゃないです。\\nでも……私なんかの絵で本当に\\n喜んでもらえるんですかね？', '10', '1', '1', '0', '0', '0.5');
