insert into wac_drama_script values (3712009, 3712, 11, '106111', 'よおーしっ！\\n壁にでかでかと描いてやったぞ！\\nこれだけの悪さをするのは\\nアタシくらいだろ！', '10', '1', '1', '0', '0', '0.5');
