insert into wac_drama_script values (8612031, 8612, 21, 'vo_wac_220511', 'vo_wac_220511_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (8612032, 8612, 11, '106011', '一人よりみんなの方が、\\n落ち着いて楽しく過ごせる……か。\\nあたしたちが囲む食卓と\\n一緒ってことかしらね。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (8612033, 8612, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (8612034, 8612, 3, '106011', 'wac_idle_doya_L', '1', '', '1', '0.2', '', '');
