insert into wac_drama_script values (8612037, 8612, 11, '105811', 'キャルちゃんの言う通りです♪\\nやばいですね☆', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (8612038, 8612, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (8612039, 8612, 3, '105811', 'wac_idle_kyapi_L', '1', '', '1', '0.2', '', '');
