insert into wac_drama_script values (8712009, 8712, 11, '106411', 'うん、いい感じね！\\n【美食殿】のみんなと一緒に\\n絵を描いて、刺激を受けたのが\\nよかったのかも。', '10', '1', '1', '0', '0', '0.5');
