insert into wac_drama_script values (11512022, 11512, 11, '102111', 'できました……！\\nえへへ、いままでの絵の中で\\n一番よく描けた気がします……♪\\n自信作、なんておおげさかな……？', '10', '1', '1', '0', '0', '0.5');
