insert into wac_drama_script values (11512027, 11512, 11, '102311', 'すごいすご～い！\\nクルミ、とっても上手！\\nぷうきちも『すげえな！』って\\nほめてるよ！', '10', '1', '1', '0', '0', '0.5');
