insert into wac_drama_script values (14312026, 14312, 21, 'vo_wac_220707', 'vo_wac_220707_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (14312027, 14312, 11, '104311', 'バ、バカ！\u3000絵筆持ったまま\\n踊るなって！\u3000尻尾に\\n絵の具がつくと落とすの大変なんだよ！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14312028, 14312, 91, '0', '', '', '', '', '', '', '');
