insert into wac_drama_script values (14712035, 14712, 21, 'vo_wac_220711', 'vo_wac_220711_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (14712036, 14712, 11, '102711', 'なにをバカなことを……\\nあなた様への愛をありったけ\\n詰め込んだ、私の絵こそが\\n一番の傑作に決まってます……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14712037, 14712, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14712038, 14712, 3, '102711', 'wac_idle_smile', '1', '', '1', '0.2', '', '');
