insert into wac_drama_script values (14712041, 14712, 11, '105111', 'あらあら、私の正確無比な\\n筆致も捨てたものじゃないわよ？\\n伊達に毎日メスを握ってる\\nわけじゃないんだから♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14712042, 14712, 91, '0', '', '', '', '', '', '', '');
