insert into wac_drama_script values (16112023, 16112, 11, '101111', 'うわあ！\u3000マスターってば\\n絵も上手なんですね！\u3000でも\\n言い方がお婆ちゃんみたいですよ？\\nなるほど、これが亀の甲羅で逃避行！', '10', '1', '1', '0', '0', '0.5');
