insert into wac_drama_script values (16412034, 16412, 21, 'vo_wac_220728', 'vo_wac_220728_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (16412035, 16412, 11, '100811', '絵の下書きはボクに任せて。\\nすべての美しさの源になる存在……\\nそれがボクだからね！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (16412036, 16412, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (16412037, 16412, 3, '100811', 'wac_idle_wish', '1', '', '1', '0.2', '', '');
