insert into wac_drama_script values (16412039, 16412, 21, 'vo_wac_220728', 'vo_wac_220728_003', '0', '0', '', '', '', '');
insert into wac_drama_script values (16412040, 16412, 11, '104511', 'それをクウカがなぞって……\\nはぁっ、もし皆さんの作業を\\n台無しにしちゃったらって思うと……\\nす、すごく……興奮しますぅ……！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (16412041, 16412, 91, '0', '', '', '', '', '', '', '');
