insert into wac_drama_script values (16412045, 16412, 11, '105511', 'あっ、道具のお片づけは\\n私がしておきました……\\nこういう地味な作業でも、\\nお役に立ててるといいんですけど……', '10', '1', '1', '0', '0', '0.5');
