insert into wac_drama_script values (16612026, 16612, 11, '100911', 'ふふ、やった！\u3000やったぞ！\\nまたしても傑作の完成だ！\\nみんなの努力が実る、この瞬間……\\n何度やっても達成感があるな！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (16612027, 16612, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (16612028, 16612, 3, '100911', 'wac_idle_kyapi_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (16612029, 16612, 3, '102711', 'wac_talk_sad_in', '0', 'wac_talk_sad_loop', '1', '0.2', '', '');
insert into wac_drama_script values (16612030, 16612, 21, 'vo_wac_220730', 'vo_wac_220730_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (16612031, 16612, 11, '102711', 'ちょ、ちょっとアンナさん……\\nあなた全身、絵の具だらけで\\n動くたびに飛び散ってますわ。\\n少し大人しくしてもらえますか？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (16612032, 16612, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (16612033, 16612, 3, '102711', 'wac_idle_sad', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (16612034, 16612, 3, '101311', 'wac_talk_smile_in', '0', 'wac_talk_smile_loop', '1', '0.2', '', '');
insert into wac_drama_script values (16612035, 16612, 21, 'vo_wac_220730', 'vo_wac_220730_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (16612036, 16612, 11, '101311', 'あははっ！\u3000そういうエリコ様も\\nおててが絵の具だらけでござるよ～！\\nむふふ、いわゆるギャップ萌え\\nというやつですな？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (16612037, 16612, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (16612038, 16612, 3, '101311', 'wac_idle_smile', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (16612039, 16612, 3, '105111', 'wac_talk_surprise_loop_shy', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (16612040, 16612, 21, 'vo_wac_220730', 'vo_wac_220730_003', '0', '0', '', '', '', '');
insert into wac_drama_script values (16612041, 16612, 11, '105111', 'まったくもう……\\nみんなして絵の具まみれじゃない。\\nって、あら？\u3000この赤いのは……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (16612042, 16612, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (16612043, 16612, 3, '105111', 'wac_idle_sad', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (16612044, 16612, 3, '105611', 'wac_talk_smile_in_L', '0', 'wac_talk_smile_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (16612045, 16612, 21, 'vo_wac_220730', 'vo_wac_220730_004', '0', '0', '', '', '', '');
insert into wac_drama_script values (16612046, 16612, 11, '105611', 'ふふ、そういうアンタも、\\nほっぺに絵の具がついてるじゃないか。\\nほら、きれいにしてやるから\\nそこに並びな、アンタたち。', '10', '1', '1', '0', '0', '0.5');
