insert into wac_drama_script values (16712013, 16712, 11, '105511', 'ふぇっ、私の絵の評判がいい！？\\n後ろで見てた人に褒められてた？\\nそ、そんな、私の絵なんて……\\nもちろん真面目に描きましたけど……', '10', '1', '1', '0', '0', '0.5');
