insert into wac_drama_script values (17412023, 17412, 11, '111011', 'はて、詳細は確認していないが、\\nなんでも国家事業の一環と聞いた。\\n期待してよかろう。我々への報酬は、\\n国家予算として計上されているはず。', '10', '1', '1', '0', '0', '0.5');
