insert into wac_drama_script values (17612022, 17612, 11, '104311', 'よーし、ざっとこんなもんだろ！\\nこういうのはあたし向きじゃないと\\n思ってたんだが、慣れてくると\\n案外楽しいもんだな♪', '10', '1', '1', '0', '0', '0.5');
