insert into wac_drama_script values (17612027, 17612, 11, '101411', '芸術という名の頭脳労働でありながら、\\n程よく体を動かせて運動にもなるしね。\\n名探偵の余暇の活動としても、\\n最適解だと思うよ♪', '10', '1', '1', '0', '0', '0.5');
