insert into wac_drama_script values (17612037, 17612, 11, '101711', 'そうだねー♪\\n遊びでもお仕事でも、\\nみんなで元気に頑張れば、\\nなんくるないさー♪', '10', '1', '1', '0', '0', '0.5');
