insert into wac_drama_script values (18812026, 18812, 11, '101311', '完☆成！\\nぐうかわ魔法少女が描く、\\nこれまたぐうかわな壁画をご覧あれ～！\\nテーマは……努力！\u3000友情！\u3000勝利！', '10', '1', '1', '0', '0', '0.5');
