insert into wac_drama_script values (18812040, 18812, 21, 'vo_wac_220821', 'vo_wac_220821_003', '0', '0', '', '', '', '');
insert into wac_drama_script values (18812041, 18812, 11, '105111', 'これってテーマなんてあったの？\\nあくまでギルドの仕事であって、\\n指示書に忠実に描けばいいと\\n思ってたんだけれど。', '10', '1', '1', '0', '0', '0.5');
