insert into wac_drama_script values (19812038, 19812, 21, 'vo_wac_220831', 'vo_wac_220831_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (19812039, 19812, 11, '100811', '美を伝えるという点では同じだよ。\\nボクだって歯磨きをするボクや\\nお昼ご飯を食べるボクがいるけど、\\n全て美しいボクには違いないでしょ？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (19812040, 19812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (19812041, 19812, 3, '100811', 'wac_idle_smile', '1', '', '1', '0.2', '', '');
