insert into wac_drama_script values (20012027, 20012, 11, '105911', 'はい、大変お上手でございます。\\nぺコリーヌさまとシェフィさまの\\n絵も、負けないくらいお上手ですよ？\\nいっぱい、褒めて差し上げますね。', '10', '1', '1', '0', '0', '0.5');
