insert into wac_drama_script values (20012032, 20012, 11, '106411', 'あ、ありがとう、コッコロさん。\\n……純粋に褒めてくれてるのは\\n分かるんだけど、どうにも\\nこそばゆい感じがするわね。', '10', '1', '1', '0', '0', '0.5');
