insert into wac_drama_script values (20612009, 20612, 11, '104211', 'なんとか、できあがりました。\\n大きな絵を描くのは、\\nライブで体を動かすのとは、\\nまた違った大変さがありますね……', '10', '1', '1', '0', '0', '0.5');
