insert into wac_drama_script values (20612012, 20612, 11, '104211', 'でも、だからこそ達成感も大きいです。\\nライブも、絵も、見る人に喜びを\\n与えられる……これからもぜひ、\\nお手伝いしていきたいですね♪', '10', '1', '1', '0', '0', '0.5');
