insert into wac_drama_script values (21112009, 21112, 11, '111011', 'しかし何だな、この作業……\\nぼく個人の芸術性は不要と言うなら、\\nぼくが筆を持つ必然はあるのだろうか。', '10', '1', '1', '0', '0', '0.5');
