insert into wac_drama_script values (21312018, 21312, 11, '110911', 'あのう、チエルまだバイト代、\\n通称国家予算もらってないんですけど。\\nコレ大丈夫なやつですかね。\\n国家バックレ案件じゃないですよね？', '10', '1', '1', '0', '0', '0.5');
