insert into wac_drama_script values (21312023, 21312, 11, '110811', 'あァ、国家そういうトコあんだよ。\\nうちも前に世界救う的なバイトしたけど\\nあいつあんときの日給まだくんないわ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (21312024, 21312, 91, '0', '', '', '', '', '', '', '');
