insert into wac_drama_script values (21312028, 21312, 11, '111011', 'まあまあ、落ちつけ後輩たち。\\n慌てる理系は貰いが少ないと言うぞ。\\n国家予算ともなれば、相応に煩雑な\\n手続きがあるのだろう。座して待て。', '10', '1', '1', '0', '0', '0.5');
