insert into wac_drama_script values (23212027, 23212, 11, '102311', 'えへへ～、楽勝だよ♪\\nもう何回か描いてるし、\\n救護院でもクルミたちと\\n練習してるからねー', '10', '1', '1', '0', '0', '0.5');
