insert into wac_drama_script values (23212032, 23212, 11, '102111', 'うん♪\\nアヤネちゃん、すっごく\\n上手になったと思うよ。\\n私も頑張らなきゃ……！', '10', '1', '1', '0', '0', '0.5');
