insert into wac_drama_script values (25212017, 25212, 21, 'vo_wac_221024', 'vo_wac_221024_000', '0', '0', '', '', '', '');
insert into wac_drama_script values (25212018, 25212, 11, '104911', 'よし、なかなか上手く描けたよ。\\nでも、弟くんへの愛を表すには\\nまだちょっと足りなかったかなあ？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (25212019, 25212, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (25212020, 25212, 3, '104911', 'wac_idle_smile', '1', '', '1', '0.2', '', '');
