insert into wac_drama_script values (25212022, 25212, 21, 'vo_wac_221024', 'vo_wac_221024_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (25212023, 25212, 11, '101111', 'そういうのは今はいいですから！\\nでもお姉ちゃん美人で頭良くて強いのに\\n絵までうまいんですねえ……\\nまさに文句上等？\u3000ってやつですよ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (25212024, 25212, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (25212025, 25212, 3, '101111', 'wac_idle_doya', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (25212026, 25212, 3, '106811', 'wac_talk_arm_crossed_in_L', '0', 'wac_talk_arm_crossed_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (25212027, 25212, 21, 'vo_wac_221024', 'vo_wac_221024_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (25212028, 25212, 11, '106811', 'それを言うなら文武両道、\\nだねリノちゃん\\nでもまあ、マスターとして\\nアタシも鼻が高いよ。……なんてね。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (25212029, 25212, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (25212030, 25212, 3, '106811', 'wac_idle_arm_crossed_L', '1', '', '1', '0.2', '', '');
