insert into wac_drama_script values (25312022, 25312, 11, '104711', '……私たちの本分は、\\n王宮のために戦うことだけれど。\\nこうして平和に絵を描いて過ごすのも、\\n悪くないと感じてしまうな。', '10', '1', '1', '0', '0', '0.5');
