insert into wac_drama_script values (25312032, 25312, 11, '107111', '団長といい、トモちゃんといい、何を\\n寝言のようなことぬかしているんだ？\\nワタシは職務熱心だからな、平時でも\\n喜んで剣を振るっているぞ♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (25312033, 25312, 91, '0', '', '', '', '', '', '', '');
