insert into wac_drama_script values (25312037, 25312, 11, '100511', 'いや～、ご立派ッスねー♪\\n……それが原因で、他の人たちと\\n揉めた回数に目をつむればッスけど。', '10', '1', '1', '0', '0', '0.5');
