insert into wac_drama_script values (25512009, 25512, 11, '100511', 'ホントにランドソルって広いッスよね～\\nみんなで壁に絵を描いてるはずなのに、\\nまだまだ終わりが見えないッス。', '10', '1', '1', '0', '0', '0.5');
