insert into wac_drama_script values (25612009, 25612, 11, '103711', '今日はこれでおしまいっと。\\nたくさん絵を描いてきたし、\\nしっかり手入れしないと筆が\\n傷んじゃいそうだな……', '10', '1', '1', '0', '0', '0.5');
