insert into wac_drama_script values (25612012, 25612, 11, '103711', '普段お世話になってる道具は\\n大切にする。\\nそういう気持ちは、剣術でも\\n美術でも大切にしないとね♪', '10', '1', '1', '0', '0', '0.5');
