insert into wac_drama_script values (26212021, 26212, 21, 'vo_wac_221103', 'vo_wac_221103_000', '0', '0', '', '', '', '');
insert into wac_drama_script values (26212022, 26212, 11, '103811', 'ふぅ……これで完成、です。\\n前よりも上手に描けたでしょうか？\\nやっぱり絵を描くのって楽しいですね。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26212023, 26212, 91, '0', '', '', '', '', '', '', '');
