insert into wac_drama_script values (26212026, 26212, 21, 'vo_wac_221103', 'vo_wac_221103_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (26212027, 26212, 11, '103311', 'んだな～♪\\nでも、シオシオ、体調は大丈夫か？\\nあんまし無茶しちゃダメだべ？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26212028, 26212, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (26212029, 26212, 3, '103311', 'wac_idle_smile_L', '1', '', '1', '0.2', '', '');
