insert into wac_drama_script values (26212032, 26212, 11, '103811', '実は、ちょっとだけ\\nフラフラ～ってしてます……\\nみんなでお絵描きするのが楽しくて、\\nはしゃぎすぎちゃったみたいで……', '10', '1', '1', '0', '0', '0.5');
