insert into wac_drama_script values (26212037, 26212, 11, '102611', 'あ、だったら、リマの背中を借りたら？\\n今日は天気もいいし、いい感じに\\nふわふわで最高だったよ～', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26212038, 26212, 91, '0', '', '', '', '', '', '', '');
