insert into wac_drama_script values (26212042, 26212, 11, '105211', 'もう、リンちゃんったら、\\nすぐに抱きついてくるんだから。\\nでも、シオリちゃんが疲れてるなら、\\n帰りはおんぶして運んであげるわよ♪', '10', '1', '1', '0', '0', '0.5');
