insert into wac_drama_script values (26222022, 26222, 11, '101411', 'よし、描けた。\\nみんなで話し合ったりして、\\nちょっと時間はかかったけど、\\n悪くない出来じゃないかな？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26222023, 26222, 91, '0', '', '', '', '', '', '', '');
