insert into wac_drama_script values (26222027, 26222, 11, '101011', 'せやねぇ♪\\nみんなでわいわいしながら、\\nまったりと描くんも楽しかったわぁ♪\\n絵にもそれが表れてます♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26222028, 26222, 91, '0', '', '', '', '', '', '', '');
