insert into wac_drama_script values (26222032, 26222, 11, '101711', 'でーじ分かるさ～！\\n見てるとこう、ワクワクしてきて\\n思わず踊りたくなるね～\\nよ～し、マコトも一緒に踊るさ～♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26222033, 26222, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (26222034, 26222, 3, '101711', 'wac_idle_smile_L', '1', '', '1', '0.2', '', '');
