insert into wac_drama_script values (26222037, 26222, 11, '104311', 'え、あたしも踊るのかよっ！？\\nていうか、さっきも踊ってただろっ？\\nあ、あんまり引っ張るなって！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26222038, 26222, 91, '0', '', '', '', '', '', '', '');
