insert into wac_drama_script values (26222042, 26222, 11, '101411', 'まったく、\\nカオリさんはしょうがないな……\\nせっかく描き終わったんだし、\\nもう少しゆっくりと見ようじゃないか。', '10', '1', '1', '0', '0', '0.5');
