insert into wac_drama_script values (26232018, 26232, 11, '109411', '……ええと、アン。\\n絵は、こんな感じでいいのかな……？\\nやっぱりアンがやった方が……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26232019, 26232, 91, '0', '', '', '', '', '', '', '');
