insert into wac_drama_script values (26232023, 26232, 11, '109211', 'そんなことない！\u3000バッチリだよ！\\nやっぱりグレアは天才かも！\\nアートの申し子で間違いない！\\nルゥもそう思うでしょ！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26232024, 26232, 91, '0', '', '', '', '', '', '', '');
