insert into wac_drama_script values (26232028, 26232, 11, '109311', 'ルゥの中にいるルゥも言ってます！\\nグレアせんぱいは天才で、申し子です！\\nルゥがラクガキの女王なら\\nせんぱいはラクガキのゴッドです！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (26232029, 26232, 91, '0', '', '', '', '', '', '', '');
