insert into wac_drama_script values (26232033, 26232, 11, '109411', 'う……\\nそ、そこまでほめられるのは\\nちょっと恥ずかしい……\\nでも、その、あ……ありがとう……', '10', '1', '1', '0', '0', '0.5');
