insert into wac_drama_script values (26512009, 26512, 11, '103311', '今回はなまらいい感じに描けたべや！\\n絵はあんま描かねぇから苦労したけんど\\nこれならその甲斐もあるってもんだべ♪', '10', '1', '1', '0', '0', '0.5');
