insert into wac_drama_script values (26612009, 26612, 11, '101711', 'やっぱり踊って歌いながら絵を描くのは\\nでーじ楽しいさ～♪\\nもっと踊って……え？\\n絵の具がはねちゃってる～？', '10', '1', '1', '0', '0', '0.5');
