insert into wac_drama_script values (27012032, 27012, 11, '103411', 'そうそう～♪\\n私もね、内なる芸術性を\\n発揮するために、麦しゅわの\\n力を借りてみたのよ～♪', '10', '1', '1', '0', '0', '0.5');
