insert into wac_drama_script values (27212009, 27212, 11, '103411', 'うっひゃは～い！\u3000麦しゅわパワ～～！\\n気持ちよ～く描けたわ～！\\nれも、ほんっとにちょ～～～っとだけ、\\n飲みすぎちゃったかも……？', '10', '1', '1', '0', '0', '0.5');
