insert into wac_drama_script values (27212012, 27212, 11, '103411', 'でもぉ～？\u3000ら～いじょ～ぶれ～～す！\\n麦しゅわがあればぁ、描けるのれす！\\nらから～……ご褒美にもういっぱ～い♪\\nじゃんじゃんいっくわよ～～！！', '10', '1', '1', '0', '0', '0.5');
