insert into wac_drama_script values (27312009, 27312, 11, '104411', 'やはりこの姿だと、作業しやすいのう！\\nふふっ、これもお主のおかげじゃな。\\nどれ、少しなら褒美をやっても良いぞ？\\nなに……絵を見れるだけで十分じゃと？', '10', '1', '1', '0', '0', '0.5');
