insert into wac_drama_script values (27312013, 27312, 11, '104411', '確かにわらわの描いた絵には\\nその価値があるとは思うが……\\nもう少し、こう……褒美らしいものでも\\n良いのだぞ？\u3000本当に良いのか？', '10', '1', '1', '0', '0', '0.5');
