insert into wac_drama_script values (27512009, 27512, 11, '103111', 'ふぅ、なんとか描き終わりましたね。\\n今回は自分の力だけで挑戦したので、\\n時間がかかってしまいました。\\nでも、良い経験になったと思います。', '10', '1', '1', '0', '0', '0.5');
