insert into wac_drama_script values (27512012, 27512, 11, '103111', '構図や色の順番を自分で考えて決める、\\n大変ですけど、楽しかったです。\\nそれに気付けたのも、\\nあなたが見守ってくれたおかげですね。', '10', '1', '1', '0', '0', '0.5');
