insert into wac_drama_script values (27612009, 27612, 11, '100811', 'ふふっ、頬についた絵の具すら、\\nボクを魅力的に見せちゃうね♪\\nそれどころか、何か新しいメイクの\\n参考になるかもしれないよ♪', '10', '1', '1', '0', '0', '0.5');
