insert into wac_drama_script values (27812025, 27812, 21, 'vo_wac_221119', 'vo_wac_221119_000', '0', '0', '', '', '', '');
insert into wac_drama_script values (27812026, 27812, 11, '104511', 'はぁっ、はぁっ……！\\nか、描いている姿を、ドＳさんに\\n後ろから黙って見られていると……\\n放置されてるみたいで……ぐふふ……♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (27812027, 27812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (27812028, 27812, 3, '104511', 'wac_idle_wish', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (27812029, 27812, 3, '103011', 'wac_talk_doya_in_L', '0', 'wac_talk_doya_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (27812030, 27812, 21, 'vo_wac_221119', 'vo_wac_221119_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (27812031, 27812, 11, '103011', 'おぉー、クウカがひいた曲線、\\nすごくきれいデス！\\nまるでウキヨエマスターみたいデスね！\\nワタシにもその技、教えてクダサイ！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (27812032, 27812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (27812033, 27812, 3, '103011', 'wac_idle_doya_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (27812034, 27812, 3, '105511', 'wac_talk_sad_in_surprise', '0', 'wac_talk_sad_loop_surprise', '1', '0.2', '', '');
insert into wac_drama_script values (27812035, 27812, 21, 'vo_wac_221119', 'vo_wac_221119_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (27812036, 27812, 11, '105511', 'ニ、ニノンさんも上手でしたけど、\\nクウカさんもすごい……！\\nでも、クウカさんが興奮してるのは、\\n違う理由のような……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (27812037, 27812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (27812038, 27812, 3, '105511', 'wac_idle_sad_surprise', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (27812039, 27812, 3, '105311', 'wac_talk_arm_crossed_in', '0', 'wac_talk_arm_crossed_loop', '1', '0.2', '', '');
insert into wac_drama_script values (27812040, 27812, 21, 'vo_wac_221119', 'vo_wac_221119_003', '0', '0', '', '', '', '');
insert into wac_drama_script values (27812041, 27812, 11, '105311', 'うむ……もはや、何も言うまい。\\nしかし共同作戦というのは悪くないな。\\nこれはチームプレイの\\n良い訓練になるぞ！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (27812042, 27812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (27812043, 27812, 3, '105311', 'wac_idle_arm_crossed', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (27812044, 27812, 3, '100811', 'wac_talk_smile_in_L', '0', 'wac_talk_smile_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (27812045, 27812, 21, 'vo_wac_221119', 'vo_wac_221119_004', '0', '0', '', '', '', '');
insert into wac_drama_script values (27812046, 27812, 11, '100811', 'ふふっ、ボクが一番\\n輝いちゃって申し訳ないけどね♪\\n流れる汗も太陽に照らされて、\\nボクを彩ってるみたいじゃないか♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (27812047, 27812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (27812048, 27812, 3, '100811', 'wac_idle_smile_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (27812049, 27812, 3, '104511', 'wac_talk_wish_in', '0', 'wac_talk_wish_loop', '1', '0.2', '', '');
insert into wac_drama_script values (27812050, 27812, 21, 'vo_wac_221119', 'vo_wac_221119_005', '0', '0', '', '', '', '');
insert into wac_drama_script values (27812051, 27812, 11, '104511', '絵を描くだけで、こ、こんなに\\n興奮できるなんて思いませんでした……\\nきっとこの後もドＳさんから絵について\\nあることないこと聞かれて……ぐふふ♪', '10', '1', '1', '0', '0', '0.5');
