insert into wac_drama_script values (28112026, 28112, 11, '102211', 'ふふん、私とアカリにかかれば、\\nこんなもんよ。\\nうんうん、アカリの方もいい感じ\\nじゃない♪', '10', '1', '1', '0', '0', '0.5');
