insert into wac_drama_script values (28112030, 28112, 21, 'vo_wac_221122', 'vo_wac_221122_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (28112031, 28112, 11, '100611', 'もちろんだよ、お姉ちゃん♪\\nでもちょっと物足りないかも？\\nもう一つくらい描いちゃダメ？', '10', '1', '1', '0', '0', '0.5');
