insert into wac_drama_script values (28112036, 28112, 11, '103111', '私ももう少し描きたい、という\\n気持ちはあるのですが……\\nミヤコさんがもう限界みたいです。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (28112037, 28112, 91, '0', '', '', '', '', '', '', '');
