insert into wac_drama_script values (28112041, 28112, 11, '100711', 'うう～、プリンはどこなの～？\\nいい加減プリンを出すの～！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (28112042, 28112, 91, '0', '', '', '', '', '', '', '');
