insert into wac_drama_script values (28112047, 28112, 11, '104411', 'さっきまで大人しく手伝っていたかと\\n思えば……\\nって、やめい！\\nわらわはプリンなど持っておらんわ！', '10', '1', '1', '0', '0', '0.5');
