insert into wac_drama_script values (28112052, 28112, 11, '102211', 'ミ、ミヤコちゃんっ！\\nイリヤさんは本当にプリンなんて\\n持ってないからっ！\\nアカリ、これ以上暴れないうちに……', '10', '1', '1', '0', '0', '0.5');
