insert into wac_drama_script values (28112057, 28112, 11, '100611', 'は～い♪\\nじゃあ、さくっと片づけて、みんなで\\n何か食べにいこう、お姉ちゃん♪', '10', '1', '1', '0', '0', '0.5');
