insert into wac_drama_script values (28212009, 28212, 11, '103711', '今日はここまでっと。\\nちゃんと道具の手入れもしたから、\\n絵の具のノリが良かったかな。\\nいい線が描けた気がするよ♪', '10', '1', '1', '0', '0', '0.5');
