insert into wac_drama_script values (28212012, 28212, 11, '103711', 'さてと、それじゃあ他の絵を眺めながら\\n見回りをしてこよう。\\nこんな平和な日々を守る為に\\n仕事も頑張らないと♪', '10', '1', '1', '0', '0', '0.5');
