insert into wac_drama_script values (28312009, 28312, 11, '104711', 'うん、依頼された部分は描けたかな。\\nランドソルを守るだけではなく、\\nこういう任務も大事だよね。\\n上手に描けているといいんだけど。', '10', '1', '1', '0', '0', '0.5');
