insert into wac_drama_script values (28312012, 28312, 11, '104711', '実は、団員からもっと息抜きを\\n覚えた方がいいと言われてね。\\nキャンプをしながら、\\n風景画を楽しむというのも良さそうだ。', '10', '1', '1', '0', '0', '0.5');
