insert into wac_drama_script values (28412021, 28412, 21, 'vo_wac_221125', 'vo_wac_221125_000', '0', '0', '', '', '', '');
insert into wac_drama_script values (28412022, 28412, 11, '100511', 'これでバッチリッス！\\nどうッスか？\\nトラタイガーみたいにかっこよく\\n描けてるんじゃないッスかね？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (28412023, 28412, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (28412024, 28412, 3, '100511', 'wac_idle_smile', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (28412025, 28412, 3, '103711', 'wac_talk_smile_in_L', '0', 'wac_talk_smile_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (28412026, 28412, 21, 'vo_wac_221125', 'vo_wac_221125_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (28412027, 28412, 11, '103711', 'ふふっ、そうだね。\\n君の憧れてるヒーローみたいに\\nちゃんと描けてるよ。\\n……一時はどうなるかと思ったけど。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (28412028, 28412, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (28412029, 28412, 3, '103711', 'wac_idle_smile_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (28412030, 28412, 3, '107111', 'wac_talk_doya_in', '0', 'wac_talk_doya_loop', '1', '0.2', '', '');
insert into wac_drama_script values (28412031, 28412, 21, 'vo_wac_221125', 'vo_wac_221125_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (28412032, 28412, 11, '107111', 'このクリスティーナが手伝う以上、\\n粗い仕事など許さん！\\nまったく、オマエたちはもう少し、\\n芸術を嗜むべきだぞ♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (28412033, 28412, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (28412034, 28412, 3, '107111', 'wac_idle_doya', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (28412035, 28412, 3, '104711', 'wac_talk_arm_crossed_in_L', '0', 'wac_talk_arm_crossed_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (28412036, 28412, 21, 'vo_wac_221125', 'vo_wac_221125_003', '0', '0', '', '', '', '');
insert into wac_drama_script values (28412037, 28412, 11, '104711', 'クリスちゃんは相変わらずだね。\\nでも、描き直したおかげで\\nさらに良い絵になったと思うよ。\\n私も鎧に絵の具がはねなくて一安心だ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (28412038, 28412, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (28412039, 28412, 3, '104711', 'wac_idle_arm_crossed_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (28412040, 28412, 3, '100511', 'wac_talk_smile_in', '0', 'wac_talk_smile_loop', '1', '0.2', '', '');
insert into wac_drama_script values (28412041, 28412, 21, 'vo_wac_221125', 'vo_wac_221125_004', '0', '0', '', '', '', '');
insert into wac_drama_script values (28412042, 28412, 11, '100511', 'ジュンさん、それにみんなも、\\n手伝ってくれてありがとうッス！\\nおかげで、ワイルドなかっこいい絵に\\n仕上がったッスよ♪', '10', '1', '1', '0', '0', '0.5');
