insert into wac_drama_script values (29012018, 29012, 11, '109211', 'うんっ！\u3000こんな感じかな！\\nたまには魔法を使わずに\\n自分の手でやるのも楽しいね！', '10', '1', '1', '0', '0', '0.5');
