insert into wac_drama_script values (29012028, 29012, 11, '109311', 'ルゥもです！\\nちょっとはみ出しちゃっても、\\nアンせんぱいは、ぜーんぶいいね！って\\n笑ってくれるです！', '10', '1', '1', '0', '0', '0.5');
