insert into wac_drama_script values (30312027, 30312, 11, '106011', 'ちょっともー\\nキリがないから、終わりにしなさいよ？\\nあと、ほっぺたにペンキがはねてる。\\n拭ってあげるから、こっちに来なさい？', '10', '1', '1', '0', '0', '0.5');
