insert into wac_drama_script values (30312032, 30312, 11, '105911', 'キャルさまも、シェフィさまの\\nお世話が板についてまいりましたね。\\nまるで本物の姉妹のようで、わたくし、\\n微笑ましい気分でございます。', '10', '1', '1', '0', '0', '0.5');
