insert into wac_drama_script values (30612009, 30612, 11, '104011', 'このお仕事っていろんなギルドが\\n参加してるから、お友達も増えると\\n思ってたんですけど、そんなこと\\nなかったですね……結構経つのに……', '10', '1', '1', '0', '0', '0.5');
