insert into wac_drama_script values (30612013, 30612, 11, '104011', 'えっ？\u3000私が気づいてないだけで、\\nみんな友達になりたがってる…？\\nど、どうしましょう、いざそうなったら\\nなにを話したらいいんです！？', '10', '1', '1', '0', '0', '0.5');
