insert into wac_drama_script values (30712009, 30712, 11, '101511', 'お絵描き、ずーっと続けてたから、\\nかなり上達してきた気がするわね～♪\\n使う道具についても、いろいろと\\nお勉強になったし。', '10', '1', '1', '0', '0', '0.5');
