insert into wac_drama_script values (30712012, 30712, 11, '101511', 'また、コツとか教えてあげるわね。\\nこの調子で一緒にお絵描きを続ければ、\\nあなたの心もますます豊かになるわ～\\n子どもの情操教育にいいって聞くし♪', '10', '1', '1', '0', '0', '0.5');
