insert into wac_drama_script values (31412009, 31412, 11, '104011', '……絵のお仕事をしていて\\n思い出したんですけど、昔、ノートに\\n「理想のマイフレンド」って絵や\\n設定を描いてた時期があったんですよ。', '10', '1', '1', '0', '0', '0.5');
